#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: OAuth M2M (Machine-to-Machine) - Service Principal
 *
 * Description: Best for automated workflows, CI/CD pipelines, and applications
 * that run without user interaction.
 *
 * Prerequisites:
 * - Service principal created in Databricks
 * - OAuth client ID and secret
 *
 * Setup:
 * 1. Create service principal in Databricks account console
 * 2. Generate OAuth client ID and secret
 * 3. Grant service principal permissions to workspace
 *
 * Run:
 * ```bash
 * DATABRICKS_HOST="https://your-workspace.cloud.databricks.com" \
 * DATABRICKS_CLIENT_ID="xxx" \
 * DATABRICKS_CLIENT_SECRET="yyy" \
 * npx ts-node examples/auth/oauth-m2m.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        clientId: process.env.DATABRICKS_CLIENT_ID,
        clientSecret: process.env.DATABRICKS_CLIENT_SECRET,
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated as service principal: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error(
            "\nMake sure you have set the following environment variables:"
        );
        console.error("  - DATABRICKS_HOST");
        console.error("  - DATABRICKS_CLIENT_ID");
        console.error("  - DATABRICKS_CLIENT_SECRET");
        process.exit(1);
    }
}

main().catch(console.error);
